<?php $title='Diagnostics';require __DIR__.'/partials/header.php';?><h1 class="h4 mb-3">System diagnostics</h1><div class="row g-3 mb-3"><?php foreach(['CPU'=>$v4['server']['cpu_cores'].' cores','CPU Steal'=>$v4['system']['cpu_steal_percent'].'%','RAM'=>round($v4['system']['memory_available']/1048576).' MB free','Swap'=>round(($v4['system']['swap_total']-$v4['system']['swap_free'])/1048576).' MB used','Disk'=>round($v4['system']['disk_free']/1073741824,1).' GB free','Load'=>implode(', ',$v4['system']['load'])]as$k=>$v):?><div class="col-md-4"><div class="card"><div class="card-body"><small class="text-secondary"><?=e($k)?></small><div><?=e((string)$v)?></div></div></div></div><?php endforeach?></div><div class="card mb-3"><div class="card-body"><strong>Architecture:</strong> <?=e($v4['server']['architecture'])?> · <strong>Profile:</strong> <?=e($v4['server']['name'])?> · <strong>Health:</strong> <?=e($v4['health']['score'].' / '.$v4['health']['status'])?><br><strong>FFmpeg PID:</strong> <?=e((string)($active['pid']??'—'))?> · <strong>Status:</strong> <?=e($active['status']??'stopped')?> · <strong>RTMP:</strong> <?=e($v4['stream']['connected']?'Connected':'Disconnected')?><br><strong>Speed:</strong> <?=e($v4['stream']['speed'].'x')?> · <strong>Bitrate:</strong> <?=e($v4['stream']['bitrate'].' kbps')?> · <strong>Dropped:</strong> <?=e((string)$v4['stream']['dropped'])?> · <strong>Restarts:</strong> <?=e((string)($active['restart_count']??0))?></div></div><?php foreach($v4['health']['warnings']as$w):?><div class="alert alert-warning"><?=e($w)?></div><?php endforeach?><?php if($streamDiagnostics):?><pre class="bg-dark text-light p-3 rounded"><?=e(json_encode($streamDiagnostics,JSON_PRETTY_PRINT))?></pre><?php endif?><?php require __DIR__.'/partials/footer.php'; ?>
